253→		}
254→		if written {
255→			installedCount++
256→		}
257→	}
258→
259→	if !silent {
260→		fmt.Println("✓ Installed git hooks (prepare-commit-msg, commit-msg, post-commit, pre-push)")
261→		fmt.Println("  Hooks delegate to the current strategy at runtime")
262→	}
263→
264→	return installedCount, nil
265→}
266→
267→// writeHookFile writes a hook file if it doesn't exist or has different content.
268→// Returns true if the file was written, false if it already had the same content.
269→func writeHookFile(path, content string) (bool, error) {
270→	// Check if file already exists with same content
271→	existing, err := os.ReadFile(path) //nolint:gosec // path is controlled
272→	if err == nil && string(existing) == content {
273→		return false, nil // Already up to date
274→	}
275→
276→	// Git hooks must be executable (0o755)
277→	if err := os.WriteFile(path, []byte(content), 0o755); err != nil { //nolint:gosec // Git hooks require executable permissions
278→		return false, fmt.Errorf("failed to write hook file %s: %w", path, err)
279→	}
280→	return true, nil
281→}
282→
283→// RemoveGitHook removes all Entire CLI git hooks from the repository.
284→// For standard hooks: removes hook files and restores .pre-entire backups.
285→// For Husky hooks: strips BEGIN/END entire blocks from .husky/<hookname> files.
286→// Returns the number of hooks removed.
287→func RemoveGitHook() (int, error) {
288→	hooksDir, err := GetHooksDir()
289→	if err != nil {
290→		return 0, err
291→	}
292→
293→	// When Husky is detected, strip blocks from user-facing hook files
294→	if huskyUserDir := getHuskyUserHooksDir(hooksDir); huskyUserDir != "" {
295→		return removeHuskyHooks(huskyUserDir)
296→	}
297→
298→	return removeStandardHooks(hooksDir)
299→}
300→
301→// removeStandardHooks removes standalone Entire hook files and restores backups.
302→func removeStandardHooks(hooksDir string) (int, error) {
303→	removed := 0
304→	var removeErrors []string
305→
306→	for _, hook := range gitHookNames {
307→		hookPath := filepath.Join(hooksDir, hook)
308→		backupPath := hookPath + backupSuffix
309→
310→		// Remove the hook if it contains our marker
311→		data, err := os.ReadFile(hookPath) //nolint:gosec // path is controlled
312→		hookIsOurs := err == nil && strings.Contains(string(data), entireHookMarker)
313→		hookExists := err == nil
314→
315→		if hookIsOurs {
316→			if err := os.Remove(hookPath); err != nil {
317→				removeErrors = append(removeErrors, fmt.Sprintf("%s: %v", hook, err))
318→				continue
319→			}
320→			removed++
321→		}
322→
323→		// Restore .pre-entire backup if it exists
324→		if fileExists(backupPath) {
325→			if hookExists && !hookIsOurs {
326→				// A non-Entire hook is present — don't overwrite it with the backup
327→				fmt.Fprintf(os.Stderr, "[entire] Warning: %s was modified since install; backup %s%s left in place\n", hook, hook, backupSuffix)
328→			} else {
329→				if err := os.Rename(backupPath, hookPath); err != nil {
330→					removeErrors = append(removeErrors, fmt.Sprintf("restore %s%s: %v", hook, backupSuffix, err))
331→				}
332→			}
333→		}
334→	}
335→
336→	if len(removeErrors) > 0 {
337→		return removed, fmt.Errorf("failed to remove hooks: %s", strings.Join(removeErrors, "; "))
338→	}
339→	return removed, nil
340→}
341→
342→// generateChainedContent appends a chain call to the base hook content,
343→// so the pre-existing hook (backed up to .pre-entire) is called after our hook.
344→func generateChainedContent(baseContent, hookName string) string {
345→	return baseContent + fmt.Sprintf(`%s
346→_entire_hook_dir="$(dirname "$0")"
347→if [ -x "$_entire_hook_dir/%s%s" ]; then
348→    "$_entire_hook_dir/%s%s" "$@"
349→fi
350→`, chainComment, hookName, backupSuffix, hookName, backupSuffix)
351→}
352→
353→// isHuskyHooksPath returns true if the given hooks directory is managed by Husky v9.
354→// Husky v9 sets core.hooksPath to .husky/_, so we detect it by path suffix.
355→func isHuskyHooksPath(hooksDir string) bool {
356→	cleaned := filepath.Clean(hooksDir)
357→	return filepath.Base(filepath.Dir(cleaned)) == ".husky" && filepath.Base(cleaned) == "_"
358→}
359→
360→// getHuskyUserHooksDir returns the Husky user-editable hooks directory (.husky/)
361→// from the Husky generated hooks directory (.husky/_), or empty string if not a Husky path
362→// or if the .husky/ directory doesn't exist on disk.
363→func getHuskyUserHooksDir(hooksDir string) string {
364→	if !isHuskyHooksPath(hooksDir) {
365→		return ""
366→	}
367→	// .husky/_  →  .husky/
368→	userDir := filepath.Dir(filepath.Clean(hooksDir))
369→	if !fileExists(userDir) {
370→		return ""
371→	}
372→	return userDir
373→}
374→
375→// huskyInjectionSpec defines hook content to inject into Husky user-facing hook files.
376→type huskyInjectionSpec struct {
377→	name    string
378→	content string // content between BEGIN/END markers (without markers themselves)
379→}
380→
381→// buildHuskyInjectionSpecs returns injection specifications for all managed hooks.
382→// The content does not include a shebang — Husky v9 user scripts run in the wrapper's shell context.
383→func buildHuskyInjectionSpecs(cmdPrefix string) []huskyInjectionSpec {
384→	return []huskyInjectionSpec{
385→		{
386→			name:    "prepare-commit-msg",
387→			content: fmt.Sprintf("# %s\n%s hooks git prepare-commit-msg \"$1\" \"$2\" 2>/dev/null || true", entireHookMarker, cmdPrefix),
388→		},
389→		{
390→			name:    "commit-msg",
391→			content: fmt.Sprintf("# %s\n# Commit-msg hook: strip trailer if no user content (allows aborting empty commits)\n%s hooks git commit-msg \"$1\" || exit 1", entireHookMarker, cmdPrefix),
392→		},
393→		{
394→			name:    "post-commit",
395→			content: fmt.Sprintf("# %s\n# Post-commit hook: condense session data if commit has Entire-Checkpoint trailer\n%s hooks git post-commit 2>/dev/null || true", entireHookMarker, cmdPrefix),
396→		},
397→		{
398→			name:    "pre-push",
399→			content: fmt.Sprintf("# %s\n# Pre-push hook: push session logs alongside user's push\n# $1 is the remote name (e.g., \"origin\")\n%s hooks git pre-push \"$1\" || true", entireHookMarker, cmdPrefix),
400→		},
401→	}
402→}
403→
404→// extractEntireBlock returns the BEGIN/END entire block from content (inclusive of markers),
405→// or empty string if not found.
406→func extractEntireBlock(content string) string {
407→	beginIdx := strings.Index(content, huskyBeginMarker)
408→	if beginIdx == -1 {
409→		return ""
410→	}
411→	endIdx := strings.Index(content, huskyEndMarker)
412→	if endIdx == -1 {
413→		return ""
414→	}
415→	return content[beginIdx : endIdx+len(huskyEndMarker)]
416→}
417→
418→// replaceEntireBlock replaces an existing BEGIN/END entire block with newBlock.
419→// If no existing block is found, returns the original content unchanged.
420→func replaceEntireBlock(content, newBlock string) string {
421→	existing := extractEntireBlock(content)
422→	if existing == "" {
423→		return content
424→	}
425→	return strings.Replace(content, existing, newBlock, 1)
426→}
427→
428→// buildEntireBlock wraps injection content in BEGIN/END markers.
429→func buildEntireBlock(injectionContent string) string {
430→	return huskyBeginMarker + "\n" + injectionContent + "\n" + huskyEndMarker
431→}
432→
433→// injectHuskyHookContent injects or updates an Entire block in a hook file's content.
434→// If the file has no existing block, the block is appended.
435→// If the file already has a block, it is replaced.
436→// Returns the new file content.
437→func injectHuskyHookContent(existingContent, injectionContent string) string {
438→	block := buildEntireBlock(injectionContent)
439→
440→	if extractEntireBlock(existingContent) != "" {
441→		return replaceEntireBlock(existingContent, block)
442→	}
443→
444→	// Append to existing content
445→	if existingContent == "" {
446→		return block + "\n"
447→	}
448→	// Ensure a newline before the block
449→	if !strings.HasSuffix(existingContent, "\n") {
450→		existingContent += "\n"
451→	}
452→	return existingContent + block + "\n"
453→}
454→
455→// removeEntireBlock strips the BEGIN/END entire block from content.
456→// Returns the cleaned content with the block removed.
457→func removeEntireBlock(content string) string {
458→	existing := extractEntireBlock(content)
459→	if existing == "" {
460→		return content
461→	}
462→	result := strings.Replace(content, existing, "", 1)
463→	// Clean up extra blank lines that may result from removal
464→	result = strings.TrimRight(result, "\n")
465→	if result != "" {
466→		result += "\n"
467→	}
468→	return result
469→}
470→
471→// installHuskyHooks injects Entire hook commands into Husky user-facing hook files (.husky/<hookname>).
472→// It also cleans up any stale standalone hooks in .husky/_/ from previous installations.
473→func installHuskyHooks(hooksDir, huskyUserDir, cmdPrefix string, silent bool) (int, error) {
474→	specs := buildHuskyInjectionSpecs(cmdPrefix)
475→	installedCount := 0
476→
477→	for _, spec := range specs {
478→		userHookPath := filepath.Join(huskyUserDir, spec.name)
479→		block := buildEntireBlock(spec.content)
480→
481→		var existingContent string
482→		data, err := os.ReadFile(userHookPath) //nolint:gosec // path is controlled
483→		if err == nil {
484→			existingContent = string(data)
485→		}
486→
487→		// Check if already has our block with same content
488→		if existingBlock := extractEntireBlock(existingContent); existingBlock == block {
489→			// Already up to date — still clean up stale hooks
490→			cleanUpStaleHuskyHook(hooksDir, spec.name)
491→			continue
492→		}
493→
494→		newContent := injectHuskyHookContent(existingContent, spec.content)
495→
496→		if err := os.WriteFile(userHookPath, []byte(newContent), 0o755); err != nil { //nolint:gosec // Hook files need executable permissions
497→			return installedCount, fmt.Errorf("failed to inject %s into Husky hook: %w", spec.name, err)
498→		}
499→		installedCount++
500→
501→		// Clean up stale standalone hook in .husky/_/ to prevent double execution
502→		cleanUpStaleHuskyHook(hooksDir, spec.name)
503→	}
504→
505→	if !silent {
506→		fmt.Println("✓ Installed git hooks into Husky user hooks (prepare-commit-msg, commit-msg, post-commit, pre-push)")
507→		fmt.Println("  Hooks injected into .husky/ hook files (survives npm install)")
508→	}
509→
510→	return installedCount, nil
511→}
512→
513→// cleanUpStaleHuskyHook removes a stale standalone Entire hook from .husky/_/ if it exists.
514→func cleanUpStaleHuskyHook(generatedHooksDir, hookName string) {
515→	hookPath := filepath.Join(generatedHooksDir, hookName)
516→	data, err := os.ReadFile(hookPath) //nolint:gosec // path is controlled
517→	if err != nil {
518→		return
519→	}
520→	if strings.Contains(string(data), entireHookMarker) {
521→		_ = os.Remove(hookPath)
522→	}
523→}
524→
525→// removeHuskyHooks strips Entire blocks from Husky user-facing hook files (.husky/<hookname>).
526→// If a file becomes empty after removal, it is deleted.
527→// Returns the number of hooks removed.
528→func removeHuskyHooks(huskyUserDir string) (int, error) {
529→	removed := 0
530→	var removeErrors []string
531→
532→	for _, hook := range gitHookNames {
533→		userHookPath := filepath.Join(huskyUserDir, hook)
534→		data, err := os.ReadFile(userHookPath) //nolint:gosec // path is controlled
535→		if err != nil {
536→			continue // File doesn't exist, nothing to remove
537→		}
538→
539→		content := string(data)
540→		if extractEntireBlock(content) == "" {
541→			continue // No Entire block in this file
542→		}
543→
544→		cleaned := removeEntireBlock(content)
545→		cleaned = strings.TrimSpace(cleaned)
546→
547→		if cleaned == "" {
548→			// File is empty after removing our block — delete it
549→			if err := os.Remove(userHookPath); err != nil {
550→				removeErrors = append(removeErrors, fmt.Sprintf("%s: %v", hook, err))
551→				continue
552→			}
553→		} else {
554→			// Write back the file without our block
555→			if err := os.WriteFile(userHookPath, []byte(cleaned+"\n"), 0o755); err != nil { //nolint:gosec // Hook files need executable permissions
556→				removeErrors = append(removeErrors, fmt.Sprintf("%s: %v", hook, err))
557→				continue
558→			}
559→		}
560→		removed++
561→	}
562→
563→	if len(removeErrors) > 0 {
564→		return removed, fmt.Errorf("failed to remove Husky hooks: %s", strings.Join(removeErrors, "; "))
565→	}
566→	return removed, nil
567→}
568→
569→// isLocalDev reads the local_dev setting from .entire/settings.json
570→// Works correctly from any subdirectory within the repository.
571→func isLocalDev() bool {
572→	s, err := settings.Load()
573→	if err != nil {
574→		return false
575→	}
576→	return s.LocalDev
577→}
