	}
}

func TestInstallGitHook_HuskyUpdateBlock(t *testing.T) {
	_, _, huskyDir := initHuskyTestRepo(t)

	// Pre-populate with an old version of the block
	hookPath := filepath.Join(huskyDir, "prepare-commit-msg")
