+func TestInstallGitHook_HuskyDirNotExists(t *testing.T) {
+	tmpDir, _ := initHooksTestRepo(t)
+
+	// Set core.hooksPath to .husky/_ but don't create .husky/ on disk
+	ctx := context.Background()
